// Atomic master record update implementation
int master_record_atomic_update(const char* path, MasterRecord* rec) {
char temp_path[512];
snprintf(temp_path, sizeof(temp_path), "%s.tmp", path);

pre.code:
// 1. Create and Write to temporary file
int fd = open(temp_path, O_WRONLY | O_CREAT | O_TRUNC, 0644);
if (fd < 0) return -1;
write(fd, rec, sizeof(MasterRecord));

// 2. IMPORTANT: Persist data to disk before rename
if (fsync(fd) != 0) {
    close(fd);
    return -1;
}
close(fd);

// 3. Atomic rename triggers metadata update in FS
if (rename(temp_path, path) != 0) {
    return -1;
}
return 0; // Atomic swap successful
